1	import React, { useState, useEffect, useMemo } from 'react';
2	import { Plus, Edit2, Trash2, Save, X, Clock, Lock, Upload, Download } from 'lucide-react';
3	import useDataStore from '../stores/dataStore';
4	import { formatDuration, formatTimeRange } from '../utils/formatTime';
5	
6	const DEFAULT_PASSWORD = 'ThisIsPasswordManualEntry';
7	
8	function ManualEntry() {
9	  const projects = useDataStore((state) => state.projects);
10	  const tasks = useDataStore((state) => state.tasks);
11	  const timeEntries = useDataStore((state) => state.timeEntries);
12	  const addTask = useDataStore((state) => state.addTask);
13	  const addTimeEntry = useDataStore((state) => state.addTimeEntry);
14	  const updateTimeEntry = useDataStore((state) => state.updateTimeEntry);
15	  const deleteTimeEntry = useDataStore((state) => state.deleteTimeEntry);
16	  const loadTasks = useDataStore((state) => state.loadTasks);
17	  const loadTimeEntries = useDataStore((state) => state.loadTimeEntries);
18	
19	  const [selectedProjectId, setSelectedProjectId] = useState('');
20	  const [taskName, setTaskName] = useState('');
21	  const [date, setDate] = useState(() => new Date().toISOString().split('T')[0]);
22	  const [startTime, setStartTime] = useState('09:00');
23	  const [endTime, setEndTime] = useState('10:00');
24	  const [endNextDay, setEndNextDay] = useState(false);
25	  const [notes, setNotes] = useState('');
26	  const [saving, setSaving] = useState(false);
27	  const [editingId, setEditingId] = useState(null);
28	  const [editStart, setEditStart] = useState('');
29	  const [editEnd, setEditEnd] = useState('');
30	  const [editNotes, setEditNotes] = useState('');
31	  const [editTaskId, setEditTaskId] = useState('');
32	  const [recentEntries, setRecentEntries] = useState([]);
33	  const [isLocked, setIsLocked] = useState(false);
34	  const [passwordInput, setPasswordInput] = useState('');
35	  const [passwordError, setPasswordError] = useState(false);
36	  const [savedPassword, setSavedPassword] = useState('');
37	  const [importing, setImporting] = useState(false);
38	  const [importResult, setImportResult] = useState(null);
39	
40	  useEffect(() => { loadTimeEntries(); }, [loadTimeEntries]);
41	
42	  useEffect(() => {
43	    const sorted = [...timeEntries].sort((a, b) => new Date(b.start_time) - new Date(a.start_time)).slice(0, 20);
44	    setRecentEntries(sorted);
45	  }, [timeEntries]);
46	
47	  // Seed default password on first launch; respect explicit removal (empty string)
48	  useEffect(() => {
49	    window.electronAPI.dbGet("SELECT value FROM settings WHERE key = 'manualEntryPassword'", []).then(async (row) => {
50	      if (!row) {
51	        await window.electronAPI.dbRun(
52	          "INSERT INTO settings (key, value) VALUES ('manualEntryPassword', ?)",
53	          [DEFAULT_PASSWORD]
54	        );
55	        setSavedPassword(DEFAULT_PASSWORD);
56	        setIsLocked(true);
57	      } else if (row.value) {
58	        setSavedPassword(row.value);
59	        setIsLocked(true);
60	      }
61	      // row.value === '' means owner explicitly removed it → stay unlocked
62	    });
63	  }, []);
64	
65	  const projectsByCustomer = {};
66	  projects.forEach((project) => {
67	    if (!projectsByCustomer[project.customer_name]) projectsByCustomer[project.customer_name] = [];
68	    projectsByCustomer[project.customer_name].push(project);
69	  });
70	
71	  // Detect overlapping entries
72	  const overlappingIds = useMemo(() => {
73	    const ids = new Set();
74	    for (let i = 0; i < recentEntries.length; i++) {
75	      for (let j = i + 1; j < recentEntries.length; j++) {
76	        const a = recentEntries[i];
77	        const b = recentEntries[j];
78	        if (!a.end_time || !b.end_time) continue;
79	        const aStart = new Date(a.start_time).getTime();
80	        const aEnd = new Date(a.end_time).getTime();
81	        const bStart = new Date(b.start_time).getTime();
82	        const bEnd = new Date(b.end_time).getTime();
83	        if (aStart < bEnd && aEnd > bStart) {
84	          ids.add(a.id);
85	          ids.add(b.id);
86	        }
87	      }
88	    }
89	    return ids;
90	  }, [recentEntries]);
91	
92	  const handleSave = async () => {
93	    if (!selectedProjectId || !taskName.trim()) { alert('Please select a project and enter a task name'); return; }
94	    if (!date || !startTime || !endTime) { alert('Please fill in date, start time and end time'); return; }
95	    setSaving(true);
96	    try {
97	      const existingTask = tasks.find(
98	        (t) => t.project_id === parseInt(selectedProjectId) && t.name.toLowerCase() === taskName.trim().toLowerCase()
99	      );
100	      let taskId;
101	      if (existingTask) {
102	        taskId = existingTask.id;
103	      } else {
104	        await addTask(parseInt(selectedProjectId), taskName.trim());
105	        await loadTasks();
106	        const updatedTasks = useDataStore.getState().tasks;
107	        const newTask = updatedTasks.find(
108	          (t) => t.project_id === parseInt(selectedProjectId) && t.name.toLowerCase() === taskName.trim().toLowerCase()
109	        );
110	        taskId = newTask.id;
111	      }
112	      const startDateTime = new Date(`${date}T${startTime}:00`);
113	      const endDate = endNextDay
114	        ? new Date(new Date(date).getTime() + 86400000).toISOString().split('T')[0]
115	        : date;
116	      const endDateTime = new Date(`${endDate}T${endTime}:00`);
117	      await addTimeEntry(taskId, startDateTime, endDateTime, notes.trim());
118	      const [h, m] = endTime.split(':').map(Number);
119	      const nextEnd = `${String((h + 1) % 24).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
120	      setTaskName('');
121	      setNotes('');
122	      setEndNextDay(false);
123	      if (endNextDay) {
124	        setDate(endDate);
125	        setStartTime(endTime);
126	        setEndTime(nextEnd);
127	      } else {
128	        setStartTime(endTime);
129	        setEndTime(nextEnd);
130	      }
131	    } catch (error) {
132	      alert('Failed to save: ' + error.message);
133	    } finally { setSaving(false); }
134	  };
135	
136	  const startEdit = (entry) => {
137	    setEditingId(entry.id);
138	    const start = new Date(entry.start_time);
139	    const end = new Date(entry.end_time);
140	    setEditStart(start.toTimeString().slice(0, 5));
141	    setEditEnd(end.toTimeString().slice(0, 5));
142	    setEditNotes(entry.notes || '');
143	    setEditTaskId(entry.task_id ? String(entry.task_id) : '');
144	  };
145	
146	  const handleUpdate = async (entry) => {
147	    try {
148	      const entryDate = new Date(entry.start_time).toISOString().split('T')[0];
149	      const newStart = new Date(`${entryDate}T${editStart}:00`);
150	      const newEnd = new Date(`${entryDate}T${editEnd}:00`);
151	      const newTaskId = editTaskId && editTaskId !== String(entry.task_id) ? parseInt(editTaskId) : null;
152	      await updateTimeEntry(entry.id, newStart, newEnd, editNotes.trim(), newTaskId);
153	      setEditingId(null);
154	    } catch (error) { alert('Failed to update: ' + error.message); }
155	  };
156	
157	  const handleDelete = async (id) => {
158	    if (!confirm('Delete this entry?')) return;
159	    try { await deleteTimeEntry(id); }
160	    catch (error) { alert('Failed to delete: ' + error.message); }
161	  };
162	
163	  const handleUnlock = () => {
164	    if (passwordInput === savedPassword) {
165	      setIsLocked(false);
166	      setPasswordError(false);
167	    } else {
168	      setPasswordError(true);
169	      setPasswordInput('');
170	    }
171	  };
172	
173	  const handleExport = async () => {
174	    try {
175	      const entries = await window.electronAPI.dbAll(
176	        `SELECT te.start_time, te.end_time, te.duration_seconds, te.notes,
177	                t.name as task, p.name as project, c.name as customer
178	         FROM time_entries te
179	         JOIN tasks t ON te.task_id = t.id
180	         JOIN projects p ON t.project_id = p.id
181	         JOIN customers c ON p.customer_id = c.id
182	         ORDER BY te.start_time`,
183	        []
184	      );
185	      const payload = {
186	        version: 1,
187	        exportedAt: new Date().toISOString(),
188	        entries: entries.map((e) => ({
189	          customer: e.customer,
190	          project: e.project,
191	          task: e.task,
192	          startTime: e.start_time,
193	          endTime: e.end_time,
194	          durationSeconds: e.duration_seconds,
195	          notes: e.notes || '',
196	        })),
197	      };
198	      const result = await window.electronAPI.exportData(payload);
199	      if (result.success) alert(`Exported ${entries.length} entries.`);
200	    } catch (error) {
201	      alert('Export failed: ' + error.message);
202	    }
203	  };
204	
205	  const handleImport = async () => {
206	    setImporting(true);
207	    setImportResult(null);
208	    try {
209	      const result = await window.electronAPI.importData();
210	      if (result.canceled) { setImporting(false); return; }
211	
212	      const { entries } = result.data;
213	      let imported = 0, createdCustomers = 0, createdProjects = 0, createdTasks = 0;
214	
215	      for (const entry of entries) {
216	        // Find or create customer
217	        let customer = await window.electronAPI.dbGet(
218	          'SELECT id FROM customers WHERE LOWER(name) = LOWER(?)',
219	          [entry.customer]
220	        );
221	        if (!customer) {
222	          await window.electronAPI.dbRun('INSERT INTO customers (name) VALUES (?)', [entry.customer]);
223	          customer = await window.electronAPI.dbGet('SELECT id FROM customers WHERE LOWER(name) = LOWER(?)', [entry.customer]);
224	          createdCustomers++;
225	        }
226	
227	        // Find or create project
228	        let project = await window.electronAPI.dbGet(
229	          'SELECT id FROM projects WHERE LOWER(name) = LOWER(?) AND customer_id = ?',
230	          [entry.project, customer.id]
231	        );
232	        if (!project) {
233	          await window.electronAPI.dbRun('INSERT INTO projects (customer_id, name) VALUES (?, ?)', [customer.id, entry.project]);
234	          project = await window.electronAPI.dbGet(
235	            'SELECT id FROM projects WHERE LOWER(name) = LOWER(?) AND customer_id = ?',
236	            [entry.project, customer.id]
237	          );
238	          createdProjects++;
239	        }
240	
241	        // Find or create task
242	        let task = await window.electronAPI.dbGet(
243	          'SELECT id FROM tasks WHERE LOWER(name) = LOWER(?) AND project_id = ?',
244	          [entry.task, project.id]
245	        );
246	        if (!task) {
247	          await window.electronAPI.dbRun('INSERT INTO tasks (project_id, name) VALUES (?, ?)', [project.id, entry.task]);
248	          task = await window.electronAPI.dbGet(
249	            'SELECT id FROM tasks WHERE LOWER(name) = LOWER(?) AND project_id = ?',
250	            [entry.task, project.id]
251	          );
252	          createdTasks++;
253	        }
254	
255	        const start = new Date(entry.startTime);
256	        const end = new Date(entry.endTime);
257	        const duration = Math.round((end - start) / 1000);
258	        await window.electronAPI.dbRun(
259	          'INSERT INTO time_entries (task_id, start_time, end_time, duration_seconds, notes) VALUES (?, ?, ?, ?, ?)',
260	          [task.id, start.toISOString(), end.toISOString(), duration, entry.notes || '']
261	        );
262	        imported++;
263	      }
264	
265	      await loadTimeEntries();
266	      setImportResult({ imported, createdCustomers, createdProjects, createdTasks });
267	    } catch (error) {
268	      alert('Import failed: ' + error.message);
269	    } finally {
270	      setImporting(false);
271	    }
272	  };
273	
274	  if (isLocked) {
275	    return (
276	      <div className="max-w-4xl mx-auto space-y-3">
277	        <div className="flex justify-end">
278	          <button onClick={handleExport}
279	            className="flex items-center gap-1 px-2.5 py-1 text-[10px] bg-white border border-gray-200 text-gray-600 rounded hover:bg-gray-50 shadow-sm transition-colors">
280	            <Download className="w-3 h-3" />
281	            Export data
282	          </button>
283	        </div>
284	        <div className="flex items-center justify-center" style={{ minHeight: 260 }}>
285	          <div className="bg-white rounded-lg shadow-sm p-8 w-72 text-center space-y-4">
286	            <Lock className="w-8 h-8 text-primary-500 mx-auto" />
287	            <div>
288	              <h2 className="text-sm font-semibold text-gray-900">Protected</h2>
289	              <p className="text-[10px] text-gray-400 mt-0.5">Enter the password to add manual entries</p>
290	            </div>
291	            <input
292	              type="password"
293	              value={passwordInput}
294	              onChange={(e) => setPasswordInput(e.target.value)}
295	              onKeyDown={(e) => e.key === 'Enter' && handleUnlock()}
296	              placeholder="Password"
297	              autoFocus
298	              className="w-full px-3 py-1.5 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent text-center"
299	            />
300	            {passwordError && <p className="text-[10px] text-red-500">Incorrect password</p>}
301	            <button onClick={handleUnlock}
302	              className="w-full px-3 py-1.5 text-xs bg-primary-500 text-white rounded hover:bg-primary-600 transition-colors">
303	              Unlock
304	            </button>
305	          </div>
306	        </div>
307	      </div>
308	    );
309	  }
310	
311	  return (
312	    <div className="max-w-4xl mx-auto space-y-3">
313	      {/* Form */}
314	      <div className="bg-white rounded-lg shadow-sm p-4">
315	        <div className="flex items-center gap-1.5 mb-3">
316	          <Clock className="w-3.5 h-3.5 text-primary-500" />
317	          <h2 className="text-xs font-semibold text-gray-900">Add Time Entry</h2>
318	        </div>
319	
320	        <div className="space-y-2">
321	          <div className="grid grid-cols-2 gap-2">
322	            <div>
323	              <label className="block text-[10px] font-medium text-gray-500 mb-0.5">Project</label>
324	              <select value={selectedProjectId} onChange={(e) => setSelectedProjectId(e.target.value)}
325	                className="w-full px-2 py-1.5 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent">
326	                <option value="">Select project...</option>
327	                {Object.entries(projectsByCustomer).map(([customerName, customerProjects]) => (
328	                  <optgroup key={customerName} label={customerName}>
329	                    {customerProjects.map((project) => (
330	                      <option key={project.id} value={project.id}>{project.name}</option>
331	                    ))}
332	                  </optgroup>
333	                ))}
334	              </select>
335	            </div>
336	            <div>
337	              <label className="block text-[10px] font-medium text-gray-500 mb-0.5">Task</label>
338	              <input type="text" value={taskName} onChange={(e) => setTaskName(e.target.value)} placeholder="Task name..."
339	                className="w-full px-2 py-1.5 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent" />
340	            </div>
341	          </div>
342	
343	          <div className="grid grid-cols-4 gap-2">
344	            <div>
345	              <label className="block text-[10px] font-medium text-gray-500 mb-0.5">Date</label>
346	              <input type="date" value={date} onChange={(e) => setDate(e.target.value)}
347	                className="w-full px-2 py-1.5 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent" />
348	            </div>
349	            <div>
350	              <label className="block text-[10px] font-medium text-gray-500 mb-0.5">Start</label>
351	              <input type="time" value={startTime}
352	                onChange={(e) => { setStartTime(e.target.value); setEndTime(e.target.value); }}
353	                className="w-full px-2 py-1.5 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent" />
354	            </div>
355	            <div>
356	              <div className="flex items-center gap-1.5 mb-0.5">
357	                <label className="text-[10px] font-medium text-gray-500">End</label>
358	                <label className="flex items-center gap-0.5 cursor-pointer">
359	                  <input type="checkbox" checked={endNextDay} onChange={(e) => setEndNextDay(e.target.checked)}
360	                    className="w-2.5 h-2.5 accent-primary-500" />
361	                  <span className="text-[10px] text-gray-400">+1 day</span>
362	                </label>
363	              </div>
364	              <input type="time" value={endTime} onChange={(e) => setEndTime(e.target.value)}
365	                className={`w-full px-2 py-1.5 text-xs border rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent ${endNextDay ? 'border-orange-300 bg-orange-50' : 'border-gray-200'}`} />
366	            </div>
367	            <div>
368	              <label className="block text-[10px] font-medium text-gray-500 mb-0.5">Notes</label>
369	              <input type="text" value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Optional..."
370	                className="w-full px-2 py-1.5 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent" />
371	            </div>
372	          </div>
373	
374	          <button onClick={handleSave} disabled={saving || !selectedProjectId || !taskName.trim()}
375	            className="w-full px-3 py-1.5 text-xs bg-primary-500 text-white rounded hover:bg-primary-600 disabled:bg-gray-300 disabled:cursor-not-allowed flex items-center justify-center gap-1 transition-colors">
376	            <Plus className="w-3.5 h-3.5" />
377	            <span>{saving ? 'Saving...' : 'Add Entry'}</span>
378	          </button>
379	        </div>
380	      </div>
381	
382	      {/* Recent Entries */}
383	      <div className="bg-white rounded-lg shadow-sm p-4">
384	        <div className="flex items-center justify-between mb-2">
385	          <div className="flex items-center gap-2">
386	            <h2 className="text-xs font-semibold text-gray-900">Recent Entries</h2>
387	            {overlappingIds.size > 0 && (
388	              <span className="text-[10px] px-1.5 py-0.5 bg-red-100 text-red-600 rounded-full">
389	                {overlappingIds.size} overlapping
390	              </span>
391	            )}
392	          </div>
393	          <div className="flex items-center gap-1.5">
394	            <button onClick={handleExport}
395	              className="flex items-center gap-1 px-2 py-1 text-[10px] border border-gray-200 text-gray-600 rounded hover:bg-gray-50 transition-colors">
396	              <Download className="w-3 h-3" />
397	              Export
398	            </button>
399	            <button onClick={handleImport} disabled={importing}
400	              className="flex items-center gap-1 px-2 py-1 text-[10px] border border-primary-200 text-primary-600 rounded hover:bg-primary-50 disabled:opacity-50 transition-colors">
401	              <Upload className="w-3 h-3" />
402	              {importing ? 'Importing…' : 'Import'}
403	            </button>
404	          </div>
405	        </div>
406	
407	        {importResult && (
408	          <div className="mb-2 px-2.5 py-1.5 bg-green-50 border border-green-200 rounded text-[10px] text-green-700">
409	            Imported {importResult.imported} entries
410	            {importResult.createdCustomers > 0 && ` · ${importResult.createdCustomers} new customer(s)`}
411	            {importResult.createdProjects > 0 && ` · ${importResult.createdProjects} new project(s)`}
412	            {importResult.createdTasks > 0 && ` · ${importResult.createdTasks} new task(s)`}
413	          </div>
414	        )}
415	
416	        {recentEntries.length === 0 ? (
417	          <p className="text-gray-400 text-center py-4 text-xs">No entries yet</p>
418	        ) : (
419	          <div className="space-y-1">
420	            {recentEntries.map((entry) => (
421	              <div key={entry.id}
422	                className={`flex items-center justify-between py-1.5 px-2 rounded transition-colors ${
423	                  overlappingIds.has(entry.id)
424	                    ? 'bg-red-50 border border-red-200 hover:bg-red-100'
425	                    : 'bg-gray-50 hover:bg-gray-100'
426	                }`}>
427	                {editingId === entry.id ? (
428	                  <div className="flex flex-col gap-1.5 flex-1">
429	                    <select value={editTaskId} onChange={(e) => setEditTaskId(e.target.value)}
430	                      className="w-full px-1.5 py-1 border border-gray-200 rounded text-xs focus:ring-2 focus:ring-primary-500">
431	                      {tasks.map((t) => (
432	                        <option key={t.id} value={t.id}>{t.customer_name} / {t.project_name} / {t.name}</option>
433	                      ))}
434	                    </select>
435	                    <div className="flex items-center gap-1.5">
436	                      <input type="time" value={editStart} onChange={(e) => setEditStart(e.target.value)}
437	                        className="px-1.5 py-1 border border-gray-200 rounded text-xs focus:ring-2 focus:ring-primary-500 w-20" />
438	                      <span className="text-gray-400 text-xs">-</span>
439	                      <input type="time" value={editEnd} onChange={(e) => setEditEnd(e.target.value)}
440	                        className="px-1.5 py-1 border border-gray-200 rounded text-xs focus:ring-2 focus:ring-primary-500 w-20" />
441	                      <input type="text" value={editNotes} onChange={(e) => setEditNotes(e.target.value)} placeholder="Notes..."
442	                        className="flex-1 px-1.5 py-1 border border-gray-200 rounded text-xs focus:ring-2 focus:ring-primary-500" />
443	                      <button onClick={() => handleUpdate(entry)} className="p-1 bg-primary-500 text-white rounded hover:bg-primary-600">
444	                        <Save className="w-3 h-3" />
445	                      </button>
446	                      <button onClick={() => setEditingId(null)} className="p-1 bg-gray-200 text-gray-600 rounded hover:bg-gray-300">
447	                        <X className="w-3 h-3" />
448	                      </button>
449	                    </div>
450	                  </div>
451	                ) : (
452	                  <>
453	                    <div className="flex-1 min-w-0">
454	                      <div className="text-xs font-medium text-gray-900 truncate">
455	                        {entry.customer_name} / {entry.project_name} / {entry.task_name}
456	                      </div>
457	                      <div className={`text-[10px] ${overlappingIds.has(entry.id) ? 'text-red-500' : 'text-gray-400'}`}>
458	                        {new Date(entry.start_time).toLocaleDateString()} &middot; {formatTimeRange(entry.start_time, entry.end_time)}
459	                        {entry.notes && ` — ${entry.notes}`}
460	                        {overlappingIds.has(entry.id) && ' ⚠ overlaps'}
461	                      </div>
462	                    </div>
463	                    <div className="flex items-center gap-1.5 ml-2">
464	                      <span className="font-mono text-xs font-medium text-gray-600">{formatDuration(entry.duration_seconds)}</span>
465	                      <button onClick={() => startEdit(entry)} className="p-1 text-primary-600 hover:bg-primary-50 rounded">
466	                        <Edit2 className="w-3 h-3" />
467	                      </button>
468	                      <button onClick={() => handleDelete(entry.id)} className="p-1 text-red-500 hover:bg-red-50 rounded">
469	                        <Trash2 className="w-3 h-3" />
470	                      </button>
471	                    </div>
472	                  </>
473	                )}
474	              </div>
475	            ))}
476	          </div>
477	        )}
478	      </div>
479	    </div>
480	  );
481	}
482	
483	export default ManualEntry;
